      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "admin": {
            "type": "boolean",
            "description": "true if the permission grants administrator access"
          },
          "write": {
            "type": "boolean",
            "description": "true if the permission grants contributor access"
          },
          "read": {
            "type": "boolean",
            "description": "true if the permission grants member access"
          }
        },
        "oneOf": [
          {
            "properties": {
              "user": {
                "type": "string",
                "description": "Name of the user this permission applies to."
              }
            },
            "required": [
              "user"
            ]
          },
          {
            "properties": {
              "group": {
                "type": "string",
                "description": "Name of the group this permission applies to."
              }
