{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "MY_PROJECT": {
      "type": "object",
      "properties": {
        "ruleLastRunDate": {
          "type": "number",
          "description": "Timestamp of the last run rule date"
        },
        "okCount": {
          "type": "number",
          "description": "Number of datasets having all is rules successful or empty"
        },
        "warningCount": {
          "type": "number",
          "description": "Number of datasets having at least one rule in warning and none in error"
        },
        "errorCount": {
          "type": "number",
          "description": "Number of datasets having at least one rule in error"
        },
        "emptyCount": {
          "type": "number",
          "description": "Number of datasets having all is rules with an empty status"
        }
      },
      "description": "The project key of a project containing at least one monitored dataset with a status"
    }
  },
  "required": [
    "MY_PROJECT"
  ],
  "additionalProperties": false
}

{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "MY_DATASET": {
      "type": "string",
      "enum": [
        "OK",
        "WARNING",
        "ERROR",
        "EMPTY"
      ],
      "description": "The current status of the dataset. If the dataset is partitioned it will be the worst status of the last built partitions."
    }
  },
  "required": [
    "MY_DATASET"
  ],
  "additionalProperties": false
}

{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "timestamp": {
        "type": "number",
        "description": "The timestamp of the day."
      },
      "datasets": {
        "type": "object",
        "properties": {
          "MY_DATASET": {
            "type": "object",
            "properties": {
              "monitored": {
                "type": "boolean",
                "description": "Indicate if the dataset was monitored on that day"
              },
              "deleted": {
                "type": "boolean",
                "description": "Indicate if the dataset was deleted on that day"
              },
              "lastRunRuleComputeTime": {
                "type": "number",
                "description": "The timestamp of the last computation date during the day"
              },
              "lastOutcome": {
                "type": "string",
                "enum": [
                  "OK",
                  "WARNING",
                  "ERROR",
                  "EMPTY"
                ],
                "description": "The last outcome of the dataset."
              },
              "worstOutcome": {
                "type": "string",
                "enum": [
                  "OK",
                  "WARNING",
                  "ERROR",
                  "EMPTY"
                ],
                "description": "The worst outcome of the dataset during the current day"
              }
            }
          }
        },
        "description": "The details of the datasets status run on that day."
      }
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "monitor": {
      "type": "boolean",
      "description": "Whether the dataset is monitored or not."
    },
    "checks": {
      "type": "array",
      "description": "The list of the rules defined on the dataset."
    }
  },
  "required": [
    "monitor",
    "checks"
  ],
  "additionalProperties": false
}

{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "id": {
      "type": "string",
      "description": "The id of the rule."
    },
    "type": {
      "type": "string",
      "description": "Type of the rule."
    },
    "autoRun": {
      "type": "boolean",
      "description": "Whether the rule will be run when a build on the dataset is triggered."
    },
    "enabled": {
      "type": "boolean",
